import{_ as s,o as a,c as n,V as l}from"./chunks/framework.24f0af87.js";const C=JSON.parse('{"title":"Database","description":"","frontmatter":{},"headers":[],"relativePath":"en/1.指南/5.数据库.md","filePath":"en/1.指南/5.数据库.md"}'),o={name:"en/1.指南/5.数据库.md"},e=l(`<h1 id="database" tabindex="-1">Database <a class="header-anchor" href="#database" aria-label="Permalink to &quot;Database&quot;">​</a></h1><p>In mxcad, you can obtain various data from converted drawings (.mxweb format files) using the mxcad npm package, such as layers, text styles, blocks, and data within graphic objects, among others.</p><p>We often need to retrieve this data, make modifications to it, and then apply these modified data to the displayed drawings. mxcad provides a database specifically for handling this data.</p><h2 id="how-to-retrieve-and-modify-data" tabindex="-1">How to Retrieve and Modify Data <a class="header-anchor" href="#how-to-retrieve-and-modify-data" aria-label="Permalink to &quot;How to Retrieve and Modify Data&quot;">​</a></h2><p>Each open drawing has an instance of <a href="https://mxcadx.gitee.io/mxcad_docs/api/classes/McDbDatabase.html" target="_blank" rel="noreferrer">McDbDatabase</a>, which is the database.</p><p>To obtain the current drawing&#39;s database, you can use the <code>MxCpp.App.getCurrentMxCAD()</code> method to get the current control instance and then call the <code>getDatabase()</code> method on that instance.</p><p>Within the database instance, you can access various tables through methods, and these tables provide ID objects <a href="./../../api/classes/McObjectId.html">McObjectId</a> that serve as references to specific data. By calling the corresponding methods, you can retrieve the actual data.</p><p>Let&#39;s take layer data as an example:</p><div class="language-ts"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">McCmColor</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">MxCpp</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">createMxCad</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;font-style:italic;">from</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">mxcad</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// Get the current control instance</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> mxcad </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> MxCpp</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">App</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">getCurrentMxCAD</span><span style="color:#A6ACCD;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// Get the layer table from the database</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> layerTable </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> mxcad</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">getDatabase</span><span style="color:#A6ACCD;">()</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">getLayerTable</span><span style="color:#A6ACCD;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// Get ID objects for all layers</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> aryId </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> layerTable</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">getAllRecordId</span><span style="color:#A6ACCD;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> layers </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> aryId</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">map</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;font-style:italic;">id</span><span style="color:#89DDFF;">)</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">=&gt;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#89DDFF;">    </span><span style="color:#676E95;font-style:italic;">// Get the layer data object for the corresponding ID</span></span>
<span class="line"><span style="color:#F07178;">    </span><span style="color:#C792EA;">let</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">layerRec</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">=</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">id</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">getMcDbLayerTableRecord</span><span style="color:#F07178;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#F07178;">    </span><span style="color:#89DDFF;font-style:italic;">if</span><span style="color:#F07178;"> (</span><span style="color:#A6ACCD;">layerRec</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">===</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">null</span><span style="color:#F07178;">) </span><span style="color:#89DDFF;font-style:italic;">return</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#F07178;">    </span><span style="color:#89DDFF;font-style:italic;">return</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">layerRec</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;">)</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// Set the color of the first layer</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> layer </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> layers[</span><span style="color:#F78C6C;">0</span><span style="color:#A6ACCD;">]</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">if</span><span style="color:#A6ACCD;"> (</span><span style="color:#89DDFF;">!</span><span style="color:#A6ACCD;">layer) </span><span style="color:#89DDFF;font-style:italic;">return</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> color </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">new</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">McCmColor</span><span style="color:#A6ACCD;">()</span></span>
<span class="line"><span style="color:#A6ACCD;">color</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">setRGB</span><span style="color:#A6ACCD;">(</span><span style="color:#F78C6C;">255</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">0</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">0</span><span style="color:#A6ACCD;">)</span></span>
<span class="line"><span style="color:#A6ACCD;">layer</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">color </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> color</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// After updating the display, you will see that all graphics on layer 0 with color-by-layer are now red</span></span>
<span class="line"><span style="color:#A6ACCD;">mxcad</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">updateDisplay</span><span style="color:#A6ACCD;">()</span></span></code></pre></div><p>As you can see, once we have obtained the data and modified the color property, the graphics on the drawing that belong to that layer will turn red when the display is updated.</p><h2 id="graphic-data" tabindex="-1">Graphic Data <a class="header-anchor" href="#graphic-data" aria-label="Permalink to &quot;Graphic Data&quot;">​</a></h2><p>Any class instance that inherits from <a href="https://mxcadx.gitee.io/mxcad_docs/api/classes/McDbObject.html" target="_blank" rel="noreferrer">McDbObject</a> is considered data within the database. Graphic data includes instances that inherit from <a href="https://mxcadx.gitee.io/mxcad_docs/api/classes/McDbObject.html" target="_blank" rel="noreferrer">McDbEntity</a>.</p><p>In <a href="./4.参数化交互绘图.html">Parametric Interactive Drawing</a>, all graphics like <a href="./../../api/classes/McDbText.html">McDbText</a>, <a href="./../../api/classes/McDbLine.html">McDbLine</a>, and others are representations of corresponding data within the database. After instantiation, they become graphic data. By modifying the properties of these objects, you can make changes to the displayed drawing.</p><p>In <a href="./4.参数化交互绘图.html#选择图形">Selecting Graphics</a>, there is a code example that intuitively demonstrates the characteristics of graphic data.</p><p>Usually, database data is accessed through objects of type <a href="./../../api/classes/McObjectId.html">McObjectId</a>.</p><h2 id="adding-and-deleting-layer-data" tabindex="-1">Adding and Deleting Layer Data <a class="header-anchor" href="#adding-and-deleting-layer-data" aria-label="Permalink to &quot;Adding and Deleting Layer Data&quot;">​</a></h2><p>Here&#39;s an example of how to add, delete, and modify layer data:</p><div class="language-ts"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">McCmColor</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">MxCpp</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">McDbLayerTableRecord</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">McDb</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;font-style:italic;">from</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">mxcad</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// Get the current control instance</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> mxcad </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> MxCpp</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">App</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">getCurrentMxCAD</span><span style="color:#A6ACCD;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// Instantiate a layer data object and set some properties for this layer</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> layer </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">new</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">McDbLayerTableRecord</span><span style="color:#A6ACCD;">()</span></span>
<span class="line"><span style="color:#A6ACCD;">layer</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">color </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">new</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">McCmColor</span><span style="color:#A6ACCD;">(</span><span style="color:#F78C6C;">0</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">0</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">0</span><span style="color:#A6ACCD;">)</span></span>
<span class="line"><span style="color:#A6ACCD;">layer</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">isFrozen </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#FF9CAC;">true</span></span>
<span class="line"><span style="color:#A6ACCD;">layer</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">isLocked </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#FF9CAC;">true</span></span>
<span class="line"><span style="color:#A6ACCD;">layer</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">isOff </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#FF9CAC;">true</span></span>
<span class="line"><span style="color:#A6ACCD;">layer</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">lineWeight </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> McDb</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">LineWeight</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">kLnWt018</span></span>
<span class="line"><span style="color:#A6ACCD;">layer</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">name </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">testLayer1</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// Get the layer table from the current control&#39;s database</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> layerTable </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> mxcad</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">getDatabase</span><span style="color:#A6ACCD;">()</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">getLayerTable</span><span style="color:#A6ACCD;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// Adding the layer data object to the layer table will return an object ID that identifies this layer data</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> objId </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> layerTable</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">add</span><span style="color:#A6ACCD;">(layer)</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// You can perform bulk add, delete, and modify operations on some layers by serializing and deserializing the layer table using JSON</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> layerJsonString </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> layerTable</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">getJson</span><span style="color:#A6ACCD;">()</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> layerJson </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> JSON</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">parse</span><span style="color:#A6ACCD;">(layerJsonString)</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// Here, we keep only the layers with the following names</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> keepLayerNames </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> [</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">0</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">排水</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">testLayer1</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">]</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> keepLayers </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> layerJson</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">filter</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;font-style:italic;">layerJsonObj</span><span style="color:#89DDFF;">)</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">=&gt;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">    </span><span style="color:#89DDFF;font-style:italic;">return</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">keepLayerNames</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">includes</span><span style="color:#F07178;">(</span><span style="color:#A6ACCD;">layerJsonObj</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">name</span><span style="color:#F07178;">)</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;">)</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> keepLayersJsonString </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> JSON</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">stringify</span><span style="color:#A6ACCD;">(keepLayers)</span></span>
<span class="line"><span style="color:#A6ACCD;">layerTable</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">setJson</span><span style="color:#A6ACCD;">(keepLayersJsonString)</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// Finally, you can use the \`has\` method to check if a layer exists and the \`get\` method to retrieve the corresponding object ID by providing the layer name</span></span>
<span class="line"><span style="color:#A6ACCD;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Is layer &#39;0&#39; present:</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> layerTable</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">has</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">0</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">))</span></span>
<span class="line"><span style="color:#A6ACCD;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Object ID for layer &#39;0&#39;:</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> layerTable</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">get</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">0</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">))</span></span></code></pre></div><p>There are also other data tables such as <a href="./../../api/classes/McDbLinetypeTable.html">McDbLinetypeTable</a> for linetypes, <a href="./../../api/classes/McDbTextStyleTable.html">McDbTextStyleTable</a> for text styles, <a href="./../../api/classes/McDbBlockTable.html">McDbBlockTable</a> for blocks, and more. They are used in a similar way to the layer table. For more information, you can click on the respective names to learn about their specific properties and methods.</p><p>These tables have similar methods for performing operations, and the specific details are not covered here. You can refer to the respective methods for more information.</p>`,20),p=[e];function t(r,c,y,D,i,A){return a(),n("div",null,p)}const d=s(o,[["render",t]]);export{C as __pageData,d as default};
